REDIS_HOST = os.getenv("REDIS_HOST", "localhost")
REDIS_PORT = int(os.getenv("REDIS_PORT", 6379))
REDIS_DB = int(os.getenv("REDIS_DB", 0))
REDIS_PASSWORD = os.getenv("REDIS_PASSWORD", None)
TOKEN_PREFIX = "oauth2_token:"
TOKEN_EXPIRY_SECONDS = 3600


redis_pool: Optional[redis.Redis] = None


async def get_redis() -> redis.Redis:
    global redis_pool
    if redis_pool is None:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available",
        )
    return redis_pool


@asynccontextmanager
async def lifespan(app: FastAPI):
    global redis_pool
    redis_pool = redis.Redis(
        host=REDIS_HOST,
        port=REDIS_PORT,
        db=REDIS_DB,
        password=REDIS_PASSWORD,
        decode_responses=True,
        max_connections=50,
    )
    try:
        await redis_pool.ping()
        print("Connected to Redis successfully")
    except Exception as e:
        print(f"Warning: Could not connect to Redis: {e}")

    yield

    if redis_pool:
        await redis_pool.aclose()
        print("Redis connection closed")


app = FastAPI(
    title="OAuth 2.0 Protected API Service",
    description="High-performance API with Redis-backed token validation",
    version="1.0.0",
    lifespan=lifespan,
)

security_scheme = HTTPBearer(auto_error=True)


class TokenData(BaseModel):
    user_id: str
    username: str
    email: str
    scopes: list[str]
    issued_at: str
    expires_at: str


class TokenResponse(BaseModel):
    access_token: str
    token_type: str = "bearer"
    expires_in: int = TOKEN_EXPIRY_SECONDS


class UserResponse(BaseModel):
    user_id: str
    username: str
    email: str
    scopes: list[str]


class MessageResponse(BaseModel):
    message: str
    timestamp: str


class ProtectedDataResponse(BaseModel):
    data: dict
    user: UserResponse
    timestamp: str


async def validate_token(
    credentials: HTTPAuthorizationCredentials = Depends(security_scheme),
    redis_client: redis.Redis = Depends(get_redis),
) -> TokenData:
    token = credentials.credentials

    if not token:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Bearer token is missing",
            headers={"WWW-Authenticate": "Bearer"},
        )

    token_key = f"{TOKEN_PREFIX}{token}"

    try:
        token_data_raw = await redis_client.get(token_key)
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Token store unavailable: {str(e)}",
        )

    if token_data_raw is None:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired token",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    try:
        token_info = json.loads(token_data_raw)
        token_data = TokenData(**token_info)
    except (json.JSONDecodeError, ValueError) as e:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail=f"Malformed token data: {str(e)}",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    expires_at = datetime.fromisoformat(token_data.expires_at)
    if datetime.utcnow() > expires_at:
        await redis_client.delete(token_key)
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token has expired",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    return token_data


def require_scopes(*required_scopes: str):
    async def scope_validator(
        token_data: TokenData = Depends(validate_token),
    ) -> TokenData:
        for scope in required_scopes:
            if scope not in token_data.scopes:
                raise HTTPException(
                    status_code=status.HTTP_403_FORBIDDEN,
                    detail=f"Insufficient scope. Required: {required_scopes}, "
                    f"granted: {token_data.scopes}",
                    headers={
                        "WWW-Authenticate": f'Bearer error="insufficient_scope", '
                        f'scope="{" ".join(required_scopes)}"'
                    },
                )
        return token_data

    return scope_validator


