@app.post("/auth/token", response_model=TokenResponse, tags=["Authentication"])
async def create_token(
    user_id: str = "user_123",
    username: str = "johndoe",
    email: str = "john@example.com",
    scopes: str = "read,write",
    redis_client: redis.Redis = Depends(get_redis),
):
    """
    Demo endpoint to generate and store a token in Redis.
    In production, this would be handled by a proper OAuth 2.0 authorization server.
    """
    access_token = secrets.token_urlsafe(48)

    now = datetime.utcnow()
    expires_at = now + timedelta(seconds=TOKEN_EXPIRY_SECONDS)

    scope_list = [s.strip() for s in scopes.split(",")]

    token_data = TokenData(
        user_id=user_id,
        username=username,
        email=email,
        scopes=scope_list,
        issued_at=now.isoformat(),
        expires_at=expires_at.isoformat(),
    )

    token_key = f"{TOKEN_PREFIX}{access_token}"

    try:
        await redis_client.setex(
            token_key,
            TOKEN_EXPIRY_SECONDS,
            json.dumps(token_data.model_dump()),
        )
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Could not store token: {str(e)}",
        )

    return TokenResponse(
        access_token=access_token,
        expires_in=TOKEN_EXPIRY_SECONDS,
    )


@app.post("/auth/revoke", response_model=MessageResponse, tags=["Authentication"])
async def revoke_token(
    token_data: TokenData = Depends(validate_token),
    credentials: HTTPAuthorizationCredentials = Depends(security_scheme),
    redis_client: redis.Redis = Depends(get_redis),
):
    """Revoke the current bearer token."""
    token_key = f"{TOKEN_PREFIX}{credentials.credentials}"

    try:
        await redis_client.delete(token_key)
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Could not revoke token: {str(e)}",
        )

    return MessageResponse(
        message="Token revoked successfully",
        timestamp=datetime.utcnow().isoformat(),
    )


